member.example:
Bind the GameObject tag property using a serialized binder field — the target GameObject is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GameObjectTagBinder _tag;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _tag;
    }


Bind the GameObject tag property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private GameObject _target;
        
        private GameObjectTagBinder Tag =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _tag;
    }

Switch the GameObject tag between two string values using a serialized binder field — the target GameObject is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GameObjectTagSwitcherBinder _isPlayer;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPlayer;
    }


Switch the GameObject tag between two string values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GameObject _target;
        
        private GameObjectTagSwitcherBinder IsPlayer => new(
            _target, trueValue: "Player", falseValue: "Untagged");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPlayer;
    }
